import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { useFilterStore, type Category, type WordClass } from '@/store/useFilterStore'

// Themen-Grid auf der Home-Page laut CLAUDE.md §1.
//
// Statt einer hardcoded Liste laden wir Counts aus vocab_medical und
// rendern jede vorhandene Kategorie (außer "unsorted") als Kachel.
// Klick auf eine Kachel setzt den Kategorie-Filter und leitet zu den
// Flashcards weiter.

type Counts = Record<string, number>

type Aggregates = {
  byCategory: Counts
  questionCount: number
}

const TILE_META: Record<Exclude<Category, 'all'>, { emoji: string; label: string; color: string }> = {
  anamnese:     { emoji: '🩺', label: 'Anamnese',     color: 'var(--red)' },
  anatomie:     { emoji: '🫀', label: 'Anatomie',     color: 'var(--green)' },
  symptome:     { emoji: '🤒', label: 'Symptome',     color: 'var(--orange)' },
  krankheiten:  { emoji: '🦠', label: 'Krankheiten',  color: 'var(--red)' },
  pharma:       { emoji: '💊', label: 'Pharma',       color: 'var(--lg)' },
  untersuchung: { emoji: '🔬', label: 'Untersuchung', color: 'var(--green)' },
  gynaekologie: { emoji: '🤰', label: 'Gynäkologie',  color: 'var(--orange)' },
  verb:         { emoji: '⚡', label: 'Verben',       color: 'var(--yellow)' },
  adjektiv:     { emoji: '🎨', label: 'Adjektive',    color: 'var(--lg)' },
  phrase:       { emoji: '💬', label: 'Phrasen',      color: 'var(--red)' }
}

const ORDER: Array<keyof typeof TILE_META> = [
  'anamnese',
  'anatomie',
  'symptome',
  'krankheiten',
  'pharma',
  'untersuchung',
  'gynaekologie',
  'verb',
  'adjektiv',
  'phrase'
]

export function ThemeGrid() {
  const [agg, setAgg] = useState<Aggregates | null>(null)
  const setCategory = useFilterStore((s) => s.setCategory)
  const setWordClass = useFilterStore((s) => s.setWordClass)
  const navigate = useNavigate()

  useEffect(() => {
    let cancelled = false

    async function load() {
      // Im MVP holen wir alle Kategorien + word_class clientseitig — 565 Rows
      // ist noch OK, GROUP BY würde eine RPC erfordern (Schema-Erweiterung).
      const { data, error } = await supabase
        .from('vocab_medical')
        .select('category, word_class')

      if (cancelled || error) return
      const byCategory: Counts = {}
      let questionCount = 0
      type Row = { category: string | null; word_class: string | null }
      for (const row of (data ?? []) as Row[]) {
        if (row.category && row.category !== 'unsorted') {
          byCategory[row.category] = (byCategory[row.category] ?? 0) + 1
        }
        if (row.word_class === 'question') {
          questionCount += 1
        }
      }
      setAgg({ byCategory, questionCount })
    }

    void load()
    return () => { cancelled = true }
  }, [])

  // Sub-set des Filters anpassen ohne den anderen zu touchen ist nicht ideal —
  // beim Themen-Klick reset wir den Wortart-Filter, beim Question-Klick reset
  // wir den Kategorie-Filter. Sonst hätten Klicks unerwartete Filter-Schnitte.
  function handleCategoryClick(cat: Category) {
    setCategory(cat)
    setWordClass('all')
    navigate('/learn/medical/flashcards')
  }

  function handleQuestionsClick() {
    setCategory('all')
    setWordClass('question' as WordClass)
    navigate('/learn/medical/flashcards')
  }

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))',
        gap: '0.7rem'
      }}
    >
      {ORDER.map((key) => {
        const count = agg?.byCategory[key] ?? 0
        const meta = TILE_META[key]
        const loading = agg === null
        const empty = !loading && count === 0

        return (
          <button
            key={key}
            disabled={empty}
            onClick={() => handleCategoryClick(key)}
            style={{
              background: 'var(--white)',
              border: `2px solid ${meta.color}`,
              borderRadius: 14,
              padding: '0.85rem',
              boxShadow: 'var(--shadow-card)',
              cursor: empty ? 'default' : 'pointer',
              textAlign: 'left',
              fontFamily: 'inherit',
              opacity: empty ? 0.4 : 1,
              transition: 'transform 100ms ease-out',
              minHeight: 110,
              display: 'flex',
              flexDirection: 'column',
              gap: 6
            }}
          >
            <div style={{ fontSize: '1.7rem', lineHeight: 1 }} aria-hidden="true">{meta.emoji}</div>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '0.95rem', color: meta.color }}>
              {meta.label}
            </div>
            <div style={{ fontSize: '0.75rem', opacity: 0.65 }}>
              {loading ? '…' : empty ? 'leer' : `${count} ${count === 1 ? 'Karte' : 'Karten'}`}
            </div>
          </button>
        )
      })}

      {/* Sonder-Tile: Anamnese-Fragen üben (Filter wordClass=question) */}
      <button
        onClick={handleQuestionsClick}
        disabled={!agg || agg.questionCount === 0}
        style={{
          background: 'var(--white)',
          // Doppel-Border für visuelle Abgrenzung von den Themen-Tiles
          border: '2px solid var(--yellow)',
          outline: '1px dashed var(--orange)',
          outlineOffset: '-6px',
          borderRadius: 14,
          padding: '0.85rem',
          boxShadow: 'var(--shadow-card)',
          cursor: !agg || agg.questionCount === 0 ? 'default' : 'pointer',
          textAlign: 'left',
          fontFamily: 'inherit',
          opacity: !agg || agg.questionCount === 0 ? 0.4 : 1,
          transition: 'transform 100ms ease-out',
          minHeight: 110,
          display: 'flex',
          flexDirection: 'column',
          gap: 6
        }}
      >
        <div style={{ fontSize: '1.7rem', lineHeight: 1 }} aria-hidden="true">❓</div>
        <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '0.95rem', color: 'var(--orange)' }}>
          Fragen üben
        </div>
        <div style={{ fontSize: '0.75rem', opacity: 0.65 }}>
          {!agg ? '…' : `${agg.questionCount} ${agg.questionCount === 1 ? 'Frage' : 'Fragen'}`}
        </div>
      </button>
    </div>
  )
}
